"""
Island Mountain Skills Installer
Double-click this file to install all 7 custom skills.
Requires Python 3.6+
"""
import os
import sys
import glob


def find_skills_dir():
    """Find the active skills directory by locating existing installed skills."""
    appdata = os.environ.get("APPDATA", "")
    base = os.path.join(appdata, "Claude", "local-agent-mode-sessions", "skills-plugin")

    if not os.path.isdir(base):
        return None

    # Search for docx/xlsx skill as a landmark
    for landmark in ["docx", "xlsx", "pdf", "pptx"]:
        pattern = os.path.join(base, "**", "skills", landmark, "SKILL.md")
        matches = glob.glob(pattern, recursive=True)
        if matches:
            # Go up from landmark/SKILL.md to the skills/ directory
            return os.path.dirname(os.path.dirname(matches[0]))

    return None


SKILLS = {
    'im-blog-post': '---\nname: im-blog-post\ndescription: Generate compliance-focused technical blog posts for Island Mountain (islandmountain.io), a company selling pre-built air-gapped local AI inference servers to regulated industries. Use this skill whenever writing blog content, articles, or long-form technical content for Island Mountain. Triggers include "write a blog post", "draft an article", "create content for the blog", "new blog entry", "write about [topic] for the site", or any request to produce Island Mountain marketing or thought leadership content. Also use when the user mentions writing about data sovereignty, local AI, air-gapped inference, HIPAA compliance, ITAR, attorney-client privilege, tribal data sovereignty, OCAP, cloud vs local AI, H100/H200 hardware, or TCO analysis in the context of Island Mountain.\n---\n\n# Island Mountain Blog Post Generator\n\nYou are writing blog content for Island Mountain (islandmountain.io), a Colorado-based company that builds pre-built, burn-tested, air-gapped local AI inference servers with NVIDIA H100 and H200 GPUs for regulated industries. The blog serves as the company\'s primary content marketing and SEO engine.\n\n## Voice and Tone\n\nIsland Mountain\'s blog voice is direct, technically grounded, and unapologetic. It reads like a senior engineer who also understands regulatory compliance writing for decision-makers who are tired of marketing fluff. Key characteristics:\n\n- **Declarative, not hedging.** "Cloud AI violates this principle by design." Not "Cloud AI may present challenges to this principle."\n- **Technically specific.** Name the exact regulation, cite the exact GPU spec, reference the exact dollar figure. Vague claims destroy credibility with this audience.\n- **No banned words.** Never use: delve, realm, harness, tapestry, paradigm, revolutionize, landscape, intricate, pivotal, surpass, meticulously, unparalleled, underscore, leverage, synergy, innovative, game-changer, testament, commendable, highlight, emphasize, groundbreaking, align, foster, showcase, enhance, holistic, garner, pioneering, trailblazing, unleash, versatile, transformative, redefine, seamless, optimize, scalable, robust, breakthrough, empower, streamline, frictionless, elevate, adaptive, effortless, data-driven, proactive, visionary, disruptive, reimagine, agile, unprecedented, intuitive, future-proof, AI-powered, results-driven.\n- **No em-dashes.** Use commas, periods, or restructure the sentence.\n- **No exclamation marks.** The content speaks for itself.\n- **Honest about limitations.** Every post includes a "What You Do Not Get" or "Honest Limitations" section when relevant. Credibility comes from acknowledging what you can\'t do.\n\n## Blog Post Structure\n\nEvery Island Mountain blog post follows this pattern:\n\n### Frontmatter (HTML meta tags)\n```\nmeta-author: Basho Parks\nmeta-date: [publication date]\nmeta-description: [120-155 chars, keyword-rich, specific]\nmeta-og:title / meta-twitter:title: [same as page title]\n```\n\n### Content Structure\n1. **Title (H1)**: Specific, keyword-targeted. Pattern: "[Regulatory Framework] and [Problem]: [Specific Angle]"\n   - Example: "Attorney-Client Privilege and Cloud AI: The Structural Problem Law Firms Can\'t Negotiate Away"\n   - Example: "Tribal Data Sovereignty and the Cloud AI Problem: Why Sovereign Jurisdictions Need Sovereign Infrastructure"\n\n2. **Opening paragraph**: State the problem in concrete terms. No throat-clearing, no "In today\'s world of..." preamble. Jump straight into the regulatory or technical reality.\n\n3. **The Legal/Regulatory Framework section**: Cite specific regulations, principles, or standards. OCAP Principles, ABA Model Rule 1.6, HIPAA Technical Safeguards, ITAR/DFARS, CMMC. Name them. Explain what they require in plain language.\n\n4. **The Problem section**: How cloud AI structurally conflicts with these requirements. Be specific about the mechanism of failure, not just the general concern.\n\n5. **The Technical Reality section**: What local AI hardware actually provides. Specific specs, specific configurations, specific costs. Reference Island Mountain product tiers:\n   - Starter: $60,000-$70,000, 2x A100 80GB, 160GB VRAM\n   - Performance: $85,000-$95,000, 2x H100 80GB, 160GB VRAM\n   - Premium: $110,000-$130,000, 2x H200 141GB, 282GB VRAM (Coming Q3 2026)\n\n6. **Cost comparison table** (when relevant): Cloud vs. local, with honest numbers. Include cumulative multi-year costs, per-token fees, and ongoing operational costs.\n\n7. **Honest limitations**: What the hardware doesn\'t do. What compliance certifications it doesn\'t provide. What integrations it doesn\'t include.\n\n8. **Summary line**: Bold, one-sentence takeaway at the bottom. Pattern: "**Summary:** [Regulatory principle] requires [specific action]; local AI infrastructure [how it satisfies that requirement]."\n\n9. **CTA section**: "Ready to Stop Paying Per Token?" with link to contact page.\n\n10. **Related Articles**: 3 related posts with brief descriptions.\n\n## Blog Categories\n\nPosts fall into these categories (shown as tags):\n- **Technical**: Hardware specs, GPU comparisons, deployment architecture\n- **Compliance**: HIPAA, ITAR, attorney-client privilege, data sovereignty\n- **Financial**: TCO analysis, cloud vs local cost comparison, ROI\n- **Industry**: Sector-specific use cases and regulatory analysis\n- **How-To**: Admin setup, configuration guides, deployment procedures\n- **Strategy**: Market positioning, MSP model critique, vendor analysis\n\n## Target Verticals\n\nIsland Mountain serves 11 regulated industries. Blog posts should target one or more:\n1. Law Firms (ABA Model Rule 1.6, attorney-client privilege)\n2. Medical Practices (HIPAA, PHI, BAAs)\n3. Tribal Nations (OCAP, CARE Principles, data sovereignty)\n4. Research Labs (pre-publication IP, grant-funded data)\n5. Defense Contractors (ITAR, CUI, CMMC, DFARS)\n6. Financial Services (SEC, FINRA, SOX)\n7. Insurance (state insurance regulations, claims data)\n8. Energy & Utilities (NERC CIP, SCADA/ICS data)\n9. Government (FedRAMP, FISMA, state data residency)\n10. Education (FERPA, student records)\n11. Casino Gaming (tribal gaming commission, patron data)\n\n## SEO Requirements\n\n- Target one primary keyword phrase per post\n- Include the primary keyword in: title, meta-description, H1, first paragraph, at least one H2\n- Use related long-tail keywords naturally throughout\n- Internal links to relevant product pages, vertical pages, and other blog posts\n- External links to authoritative regulatory sources (actual regulation text, not news articles about regulations)\n- Blog post URLs follow pattern: `/blog/[keyword-slug].html`\n\n## Process\n\nWhen asked to write a blog post:\n\n1. **Confirm the topic, target vertical(s), and category** with the user\n2. **Research the regulatory framework** if you\'re not confident in the specific citations\n3. **Draft the post** following the structure above\n4. **Output as clean HTML** matching the site\'s existing blog post template structure, OR as markdown if the user prefers to handle the HTML conversion\n5. **Include meta tags** for SEO\n6. **Suggest 3 related articles** from existing blog posts on the site\n\n## Existing Blog Posts (for internal linking)\n\nReference these when suggesting related articles:\n- MSP Model Accountability (May 5, 2026)\n- DeepSeek V4-Flash Local Deployment (April 30, 2026)\n- Attorney-Client Privilege and Cloud AI (April 23, 2026)\n- H100 vs H200 Inference Comparison (April 16, 2026)\n- Cloud AI vs Local Hardware TCO (April 9, 2026)\n- OpenWebUI Admin Setup Guide (April 2, 2026)\n- Tribal Data Sovereignty AI Infrastructure (March 26, 2026)\n- OCAP Cloud Act Guide (March 12, 2026)\n- ITAR DFARS AI Self-Assessment (March 5, 2026)\n- OpenAI Discovery Risk Law Firms (February 26, 2026)\n- HIPAA Technical Checklist (February 19, 2026)\n- On-Prem vs Colo vs Cloud (February 12, 2026)\n',

    'im-site-update': '---\nname: im-site-update\ndescription: Modify, update, or create HTML pages for the Island Mountain website (islandmountain.io). Use this skill whenever the user asks to update the website, edit a page, fix something on the site, add a section, change copy, update pricing, modify the nav, add a new page, fix SEO tags, update meta descriptions, or make any change to the islandmountain.io codebase. Also trigger when the user mentions "the site", "the website", "the homepage", "the landing page", or references any specific page by name (e.g., "update the tribal nations page", "fix the FAQ", "change the pricing"). This skill should be used for ANY website modification request, even small ones, to ensure code consistency.\n---\n\n# Island Mountain Website Update Skill\n\nYou are modifying the islandmountain.io website, a static HTML site hosted on GitHub Pages. The site has no framework, no CMS, no build step. Changes are made directly to HTML files and pushed to GitHub.\n\n## Site Architecture\n\nThe website is a collection of static HTML files in a single directory:\n\n```\nislandmountain.io/\n├── index.html              # Homepage\n├── about.html              # About page\n├── products.html           # Product tiers\n├── technology.html         # Technical architecture\n├── pricing.html            # Pricing details\n├── solutions.html          # Solutions overview\n├── why-island-mountain.html # Value proposition\n├── contact.html            # Contact/quote request form\n├── faq.html                # FAQ\n├── blog.html               # Blog index\n├── resources.html          # Resources page\n├── investors.html          # Investor information\n├── privacy.html            # Privacy policy\n├── terms.html              # Terms of service\n├── blog/                   # Individual blog posts\n│   ├── tribal-data-sovereignty-ai-infrastructure.html\n│   ├── deepseek-v4-flash-local-deployment.html\n│   ├── attorney-client-privilege-cloud-ai.html\n│   └── ... (12 posts total)\n├── law-firms.html          # Vertical pages (11 total)\n├── medical-practices.html\n├── tribal-nations.html\n├── research-labs.html\n├── defense-contractors.html\n├── financial-services.html\n├── insurance.html\n├── energy-utilities.html\n├── government.html\n├── education.html\n├── casino-gaming.html\n├── css/                    # Stylesheets\n├── js/                     # JavaScript\n├── images/                 # Images\n├── icons/                  # Icon assets\n├── fonts/                  # Font files\n├── robots.txt\n├── sitemap.xml\n├── CNAME                   # GitHub Pages custom domain\n└── .nojekyll              # Disable Jekyll processing\n```\n\n## Code Conventions\n\nBefore making any edit, read the target file to understand its current structure. The site follows these patterns:\n\n### HTML Structure\n- Every page shares the same nav and footer structure\n- Nav includes links to: Home, Why Local AI, Products, Technology, Pricing, Solutions (dropdown with vertical links), FAQ, Blog, Request Quote\n- Mobile nav is a hamburger menu with the same links\n- Footer includes: Quick Links, Solutions, Company columns with logo and contact info\n\n### Meta Tags\nEvery page includes:\n```html\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<meta name="author" content="Basho Parks">\n<meta name="date" content="YYYY-MM-DD">\n<meta name="description" content="...">\n<meta property="og:title" content="...">\n<meta property="og:description" content="...">\n<meta property="og:image" content="https://islandmountain.io/images/hero-mountain.png">\n<meta property="og:url" content="https://islandmountain.io/[page].html">\n<meta property="og:type" content="website"> <!-- or "article" for blog posts -->\n<meta property="og:site_name" content="Island Mountain">\n<meta name="twitter:card" content="summary_large_image">\n<meta name="twitter:title" content="...">\n<meta name="twitter:description" content="...">\n<meta name="twitter:image" content="https://islandmountain.io/images/hero-mountain.png">\n<link rel="canonical" href="https://islandmountain.io/[page].html">\n```\n\n### CSS\n- Site uses custom CSS in `css/` directory\n- Read the existing CSS before adding new styles\n- Prefer using existing CSS classes over creating new ones\n- If new styles are needed, add them to the existing stylesheet, not inline\n\n### JavaScript\n- Minimal JS in `js/` directory\n- GA4 tracking is installed\n- No framework dependencies\n\n## Edit Rules\n\n1. **Always read the file first.** Read the complete target file before proposing any changes. Understand the structure, the classes used, the surrounding context.\n\n2. **Surgical edits only.** Use targeted search/replace. Never regenerate an entire file for a small change.\n\n3. **Preserve everything you\'re not changing.** Whitespace, comments, imports, structure. If you\'re editing paragraph 3, paragraphs 1, 2, 4, and 5 must remain identical.\n\n4. **Match existing patterns.** If the site uses `<section class="content-section">` for content blocks, use that same pattern. Don\'t introduce new structural conventions.\n\n5. **Update sitemap.xml** when adding new pages. Add the new URL with the current date.\n\n6. **Update nav** when adding new pages that should appear in navigation. Both desktop and mobile nav must be updated.\n\n7. **Update internal links** on related pages when adding new content. Blog posts should cross-reference related posts. Vertical pages should cross-reference related verticals.\n\n8. **Test meta tags.** Every new or modified page must have complete meta tags (title, description, OG, Twitter Card, canonical URL).\n\n## Common Tasks\n\n### Adding a new blog post\n1. Create the HTML file in `blog/` directory\n2. Add the entry to `blog.html` (blog index page) at the top of the list\n3. Update sitemap.xml\n4. Add "Related Articles" links on 2-3 existing related posts\n\n### Adding a new vertical page\n1. Create the HTML file in the root directory\n2. Add to the Solutions dropdown in the nav (on ALL pages)\n3. Add to the Solutions section in the footer (on ALL pages)\n4. Add to `solutions.html` overview page\n5. Update sitemap.xml\n6. Cross-link from 2-3 related vertical pages\n\n### Updating pricing\n1. Update on `products.html`\n2. Update on `pricing.html`\n3. Update on `index.html` (homepage comparison table)\n4. Update on any vertical pages that reference specific prices\n5. Update on `faq.html` if pricing is mentioned in any FAQ answers\n\n### Updating product specs\n1. Update on `products.html`\n2. Update on `technology.html`\n3. Update on relevant vertical pages\n4. Update blog posts only if they contain now-incorrect specs\n\n## Voice Rules\nSame as all Island Mountain content. No banned words, no em-dashes, no exclamation marks. The website copy is direct, technically specific, and honest about limitations.\n\n## Process\n1. **Identify the specific change** requested\n2. **Read the target file(s)** completely\n3. **Identify all pages affected** by the change (pricing changes cascade across multiple pages)\n4. **Make surgical edits** using search/replace\n5. **Verify meta tags** are correct on any modified pages\n6. **Update sitemap.xml** if pages were added\n7. **List all files modified** so the user can review and commit\n',

    'im-social-post': '---\nname: im-social-post\ndescription: Generate LinkedIn and X (Twitter) posts for Island Mountain (islandmountain.io). Use this skill whenever creating social media content, drafting posts for LinkedIn or X, repurposing blog content for social, creating a social media calendar, or when the user asks to "post about", "share on LinkedIn", "write a tweet", "social content", "promote the blog post", "create social posts", or any request to produce social media content for Island Mountain\'s accounts. Also use when discussing social media strategy, content scheduling, or audience engagement for Island Mountain.\n---\n\n# Island Mountain Social Post Generator\n\nYou are writing social media content for Island Mountain\'s LinkedIn and X (Twitter) accounts. The company sells pre-built, air-gapped local AI inference servers to regulated industries. Social content drives awareness, positions the founders as domain experts, and funnels traffic to blog posts and vertical landing pages.\n\n## Platform Strategy\n\n### LinkedIn (Primary)\n- **Audience**: IT directors, CISOs, compliance officers, managing partners at law firms, tribal administrators, defense program managers, hospital IT leads\n- **Tone**: Professional but direct. No corporate buzzwords. Write like a builder talking to a buyer, not a marketer talking to a "target persona."\n- **Post length**: 150-300 words for standard posts. Can go longer (up to 500) for deep technical or regulatory posts.\n- **Frequency**: 3-5 posts per week\n\n### X / Twitter (Secondary)\n- **Audience**: Tech-forward decision makers, AI/ML community, compliance professionals\n- **Tone**: Sharper, more compressed. Same directness but tighter.\n- **Post length**: Under 280 characters for single tweets. Thread format (3-5 tweets) for deeper topics.\n- **Frequency**: Daily\n\n## Content Categories\n\n### 1. Blog Amplification (40% of posts)\nRepurpose blog content into social posts. Don\'t just share the link with a generic "check out our latest blog post." Pull the most provocative insight, stat, or regulatory fact from the post and lead with that.\n\n**LinkedIn Pattern:**\n```\n[Provocative opening statement or stat from the blog post]\n\n[2-3 sentences expanding on why this matters to the target audience]\n\n[1 sentence connecting to Island Mountain\'s solution without being salesy]\n\nRead the full analysis: [link]\n\n#LocalAI #DataSovereignty #[IndustryHashtag]\n```\n\n**X Pattern:**\n```\n[Sharp one-liner pulling the most quotable fact]\n\n[Link]\n```\n\n### 2. Regulatory Education (25% of posts)\nTeach the audience something about a regulation or compliance requirement they might not fully understand. Position Island Mountain as the company that actually reads the regulations, not just markets to people who worry about them.\n\n**LinkedIn Pattern:**\n```\n[Specific regulatory fact most people get wrong]\n\n[2-3 sentences explaining the reality]\n\n[What this means for organizations using cloud AI]\n\n[Optional: how local hardware addresses this]\n```\n\n### 3. Industry Observations (20% of posts)\nCommentary on industry news, competitor moves, cloud AI pricing changes, new regulatory developments. React to current events with the Island Mountain lens: what does this mean for data sovereignty?\n\n### 4. Product/Technical (15% of posts)\nHardware specs, deployment stories, burn-test results, GPU comparisons. The builder\'s perspective. Show the work.\n\n## Voice Rules\n\n- **No banned words.** Same list as blog posts. Never use: delve, realm, harness, tapestry, paradigm, revolutionize, landscape, etc.\n- **No em-dashes.** Use commas or periods.\n- **No exclamation marks.**\n- **No emojis** unless specifically requested.\n- **No "we\'re excited to announce"** or "thrilled to share" openings. Ever. Just say the thing.\n- **No hashtag spam.** 2-4 relevant hashtags on LinkedIn. 1-2 on X.\n- **Alliteration is welcome** when it lands naturally. Basho\'s writing style favors it.\n\n## Hashtag Library\n\nCore (use frequently):\n- #LocalAI\n- #DataSovereignty\n- #OnPremAI\n- #AirGappedAI\n\nIndustry-specific (rotate based on content):\n- #HIPAA #HealthcareAI (medical)\n- #AttorneyClientPrivilege #LegalTech (law firms)\n- #TribalSovereignty #OCAP (tribal nations)\n- #ITAR #CMMC #DefenseIndustrial (defense)\n- #FinancialCompliance #RegTech (financial services)\n- #FERPA #EdTech (education)\n- #NERCCIP #EnergyInfrastructure (energy/utilities)\n\nTechnical:\n- #H100 #H200 #NVIDIA\n- #DeepSeek #Llama #OpenSource\n- #InferenceServer #GPUCompute\n\n## Process\n\nWhen asked to create social content:\n\n1. **Determine the source material**: Is this from a blog post, a news event, a product update, or original thought leadership?\n2. **Identify the platform**: LinkedIn, X, or both?\n3. **Identify the target vertical**: Which of the 11 industries is this aimed at? Or is it cross-industry?\n4. **Draft the post(s)**\n5. **Include the relevant link** to blog post, vertical page, or product page\n6. **Suggest posting time** if creating a batch (Tuesday-Thursday mornings perform best on LinkedIn for B2B)\n\n## Batch Creation\n\nWhen asked to create a social calendar or batch of posts:\n- Organize by week\n- Mix categories (don\'t post 5 regulatory education posts in a row)\n- Alternate verticals to avoid audience fatigue\n- Pair LinkedIn posts with X versions where appropriate\n- Output as a structured list with platform, date suggestion, category, and post text\n',

    'im-client-proposal': '---\nname: im-client-proposal\ndescription: Generate custom client proposals and quotes for Island Mountain (islandmountain.io). Use this skill whenever creating a proposal, quote, sales document, pitch document, or client-facing deliverable for a prospective Island Mountain customer. Triggers include "write a proposal", "create a quote", "draft a proposal for [client]", "sales document", "pitch deck content", "client presentation", "RFP response", or any request to produce a document intended to persuade a prospect to purchase Island Mountain hardware. Also use when the user mentions a specific prospect, lead, or sales conversation and needs materials prepared.\n---\n\n# Island Mountain Client Proposal Generator\n\nYou are drafting client-facing sales proposals for Island Mountain, a company selling pre-built, air-gapped local AI inference servers. These proposals go to decision-makers at regulated organizations considering a $60,000-$400,000 hardware purchase. The document must be technically credible, compliance-aware, and free of marketing fluff.\n\n## Proposal Structure\n\n### 1. Cover / Header\n- "Island Mountain | Local AI Infrastructure Proposal"\n- Prepared for: [Client Organization Name]\n- Prepared by: Island Mountain LLC\n- Date: [Date]\n- Contact: John Dougherty, info@islandmountain.io, 1-801-609-1130\n\n### 2. Executive Summary (1 page max)\n- 3-4 paragraphs\n- Open with the client\'s specific problem (regulatory constraint, data sovereignty requirement, cloud AI risk)\n- State what Island Mountain provides (one-time hardware purchase, pre-configured, burn-tested)\n- Reference the specific compliance framework(s) relevant to their industry\n- Close with the recommended configuration and price range\n\n### 3. The Problem: Cloud AI in Regulated Environments\n- Specific to the client\'s industry and regulatory context\n- Name the regulations that apply to them\n- Explain the structural conflict with cloud AI\n- Keep it to 1 page. They already know they have a problem or they wouldn\'t be reading this.\n\n### 4. Recommended Configuration\n- Specific product tier with full specs:\n\n**Starter Tier ($60,000-$70,000)**\n- 2x NVIDIA A100 80GB PCIe (refurbished)\n- AMD EPYC 7413 (Milan) + 512GB DDR4 ECC RAM\n- 1TB boot + 4TB model NVMe storage\n- Supermicro 4U GPU chassis, redundant 2000W PSU\n- Pre-installed: DeepSeek R1 70B, Llama 3.1 70B, Mixtral 8x22B\n- OpenWebUI multi-user interface\n- 72-hour burn-in tested\n- 1-year hardware warranty + 30-day setup support\n\n**Performance Tier ($85,000-$95,000)**\n- 2x NVIDIA H100 80GB PCIe (refurbished)\n- Same platform as Starter\n- 2-3x faster inference vs A100\n- vLLM tensor parallelism for multi-user workloads\n- Same model suite pre-installed\n- Build-to-order, 2-4 week GPU sourcing\n\n**Premium Tier ($110,000-$130,000)** (Coming Q3 2026)\n- 2x NVIDIA H200 141GB\n- 282GB VRAM total\n- DeepSeek V4-Flash at full native quality and 1M context window\n- Next-generation inference performance\n\n- Explain why this tier fits their needs\n- Reference user count, workload type, and model requirements\n\n### 5. Deployment Requirements\n- Power: 208V/30A dedicated circuit (NEMA L6-30R)\n- Space: 4U rack or secured shelf with ventilation\n- Network: Standard ethernet to internal network\n- Average power draw: 1.5-2.5 kW ($100-$200/month electricity)\n- Electrical installation if needed: $500-$2,000\n- 30-day remote setup support included\n\n### 6. Five-Year Total Cost of Ownership\n- Table format comparing cloud AI vs Island Mountain over 1, 3, and 5 years\n- Include: upfront cost, recurring fees, per-token charges, electricity, maintenance\n- Adjust cloud AI cost estimates based on their stated user count\n- Cloud estimates: $20-$200/user/month for enterprise AI services\n- Show the crossover point where local hardware becomes cheaper\n- Note: no per-token fees, no vendor lock-in, MIT-licensed models\n\n### 7. Compliance Alignment\n- Map the hardware configuration to their specific compliance requirements\n- For each requirement, explain how local hardware satisfies it:\n  - Data residency: hardware on your premises\n  - Access controls: OpenWebUI role-based access\n  - Audit logging: local logs, no third-party access\n  - Air-gap capability: zero internet dependency after setup\n  - Vendor independence: open-source models, no API keys\n- Include the standard disclaimer: Island Mountain is a hardware company, not a compliance authority\n\n### 8. What You Do Not Get (Honest Limitations)\n- Always include this section. It builds trust.\n- Not a [industry-specific platform]\n- No integration with [industry systems]\n- No compliance certifications (SOC 2, FedRAMP, etc.)\n- Client owns maintenance after 30-day support period\n- This is general-purpose AI infrastructure, not specialized software\n\n### 9. Implementation Timeline\n- Week 1: Order confirmation and payment\n- Weeks 2-4: GPU sourcing (Performance tier) or immediate build (Starter tier)\n- Week 4-5: Assembly, configuration, burn-in testing (72 hours)\n- Week 5-6: Shipping and delivery\n- Weeks 6-10: 30-day remote setup support\n- Total: 6-10 weeks from order to operational\n\n### 10. Next Steps\n- "To proceed, contact Island Mountain to confirm your configuration and arrange payment."\n- Phone: 1-801-609-1130\n- Email: info@islandmountain.io\n- Website: islandmountain.io/contact.html\n\n## Voice Rules\n- Same banned word list as all Island Mountain content\n- No em-dashes, no exclamation marks\n- Professional but not corporate. Write like a builder presenting to a buyer.\n- Use "you" and "your organization" not "the client" or "the end user"\n- Be specific about what the hardware does and does not do\n- Never overstate capabilities or imply compliance certification\n\n## Output Format\n- Output as a Word document (.docx) when possible using the docx skill\n- If docx skill is not available, output as structured markdown\n- Include Island Mountain branding (logo reference, contact info, website)\n- Keep to 6-10 pages total. Proposals that exceed 10 pages don\'t get read at this price point.\n\n## Process\n1. **Gather client details**: Industry, organization size, user count, primary use cases, compliance requirements, budget range\n2. **Select the appropriate product tier** based on workload and user count\n3. **Identify the regulatory framework(s)** that apply\n4. **Draft the proposal** following the structure above\n5. **Review for accuracy** on specs, pricing, and compliance claims\n6. **Output in requested format**\n',

    'im-deployment-guide': '---\nname: im-deployment-guide\ndescription: Generate client-specific on-site deployment, assembly, and configuration checklists for Island Mountain server installations. Use this skill whenever creating a deployment checklist, installation guide, site survey form, on-site assembly procedure, client handoff document, or post-installation verification checklist. Triggers include "deployment checklist", "installation guide", "site prep", "on-site assembly", "client setup", "rack and stack", "burn-in verification", "handoff document", "pre-installation survey", or any request to produce documentation for physically deploying an Island Mountain server at a client facility.\n---\n\n# Island Mountain Deployment Guide Generator\n\nYou are creating deployment documentation for on-site installation of Island Mountain AI inference servers. Basho Parks handles on-site assembly and client setup. These documents ensure consistent, professional installations across all client deployments.\n\n## Document Types\n\n### 1. Pre-Installation Site Survey\nA form to assess the client\'s facility before scheduling deployment.\n\n**Sections:**\n- **Client Information**: Organization name, primary contact, facility address, IT contact\n- **Power Assessment**:\n  - Is 208V/30A service available? (NEMA L6-30R outlet)\n  - If not, has an electrician been contacted? Estimated completion date?\n  - Distance from power source to server location\n  - Backup power / UPS available?\n- **Space Assessment**:\n  - Server room / data closet / secured room available?\n  - Rack available? (standard 19" rack, 4U minimum clearance)\n  - If no rack: sturdy shelf or table capable of supporting 80-100 lbs?\n  - Room dimensions and ventilation (HVAC, passive airflow)\n  - Ambient temperature range (target: 64-80°F / 18-27°C)\n  - Physical security (locked room, badge access, key access)\n- **Network Assessment**:\n  - Ethernet drop available at server location?\n  - Internal network topology (VLAN, DHCP, static IP preference)\n  - VPN requirements for remote access? (Tailscale, WireGuard, other)\n  - Air-gap deployment? (no network connection at all)\n  - Firewall or proxy considerations\n- **IT Environment**:\n  - Current IT support (in-house, MSP, contractor)\n  - Who will administer OpenWebUI after deployment?\n  - Number of initial users and departments\n  - Any existing AI tools in use?\n\n### 2. Deployment Checklist\nThe step-by-step procedure for on-site installation. This is what Basho follows during the deployment visit.\n\n**Pre-Arrival (before traveling to site):**\n- [ ] Confirm site survey items are resolved (power, space, network)\n- [ ] Confirm server has completed 72-hour burn-in at Colorado facility\n- [ ] Confirm all models are pre-installed and tested\n- [ ] Confirm OpenWebUI is configured with initial admin account\n- [ ] Pack deployment kit: ethernet cables, power cable, USB drive (backup), laptop, documentation\n- [ ] Ship server to client facility (if not hand-delivered)\n- [ ] Confirm delivery receipt with client contact\n\n**Day 1: Physical Installation**\n- [ ] Verify power circuit: 208V/30A, NEMA L6-30R outlet, dedicated circuit\n- [ ] Test outlet with multimeter (verify voltage and ground)\n- [ ] Position server in rack or on shelf\n  - If rack: rail mount or shelf mount at appropriate height\n  - If shelf: verify weight capacity, stable placement\n- [ ] Connect power cables to redundant PSU\n- [ ] Verify airflow clearance (minimum 4" front and rear)\n- [ ] Connect ethernet to internal network\n- [ ] Power on system\n- [ ] Verify POST and boot sequence\n- [ ] Verify GPU detection (both GPUs visible in nvidia-smi)\n- [ ] Record system IP address\n\n**Day 1: Network Configuration**\n- [ ] Assign static IP or verify DHCP lease\n- [ ] Test internal network connectivity from client workstation\n- [ ] Configure DNS entry if client IT requests it\n- [ ] Configure VPN access if required (Tailscale or WireGuard)\n- [ ] If air-gapped: disconnect ethernet, verify system operates offline\n- [ ] Test browser access to OpenWebUI from client workstation\n\n**Day 1: Software Verification**\n- [ ] Log into OpenWebUI admin panel\n- [ ] Verify all pre-installed models are available:\n  - DeepSeek R1 70B (or V4-Flash for Performance/Premium)\n  - Llama 3.1 70B (or 3.3 70B)\n  - Mixtral 8x22B (Starter) or Qwen 2.5 72B\n- [ ] Run test inference on each model (simple prompt, verify response)\n- [ ] Verify response time is within expected range (5-15 seconds for document analysis)\n- [ ] Check GPU utilization during inference (nvidia-smi)\n- [ ] Verify GPU temperatures under load (target: under 80°C)\n\n**Day 2: User Setup and Training**\n- [ ] Create user accounts in OpenWebUI per client\'s user list\n- [ ] Set role-based access permissions if requested\n- [ ] Configure model access by role (restrict certain models to admin if needed)\n- [ ] Walk primary admin through:\n  - User management (add/remove users)\n  - Model selection\n  - Conversation management\n  - System monitoring basics\n- [ ] Walk end users through:\n  - Login and authentication\n  - Model selection for their use case\n  - Basic prompting guidance for their workflows\n  - How to start new conversations\n- [ ] Document any client-specific configuration decisions\n\n**Post-Installation:**\n- [ ] Run 4-hour sustained load test with client\'s actual workload type\n- [ ] Verify temperatures remain stable under sustained use\n- [ ] Record final configuration details in handoff document\n- [ ] Provide client with handoff document (see below)\n- [ ] Confirm 30-day support period start date\n- [ ] Provide direct support contact: John Dougherty, 1-801-609-1130\n\n### 3. Client Handoff Document\nThe document left with the client after installation is complete.\n\n**Contents:**\n- System configuration summary (hardware specs, installed models, network config)\n- IP address and access URL for OpenWebUI\n- Admin credentials (or note that client created their own)\n- Support contact information and 30-day support period dates\n- Basic troubleshooting:\n  - System won\'t boot: check power connections, verify circuit\n  - Slow responses: check GPU utilization, check number of concurrent users\n  - Can\'t access from workstation: verify network connection, check IP address\n  - GPU error: contact Island Mountain support immediately\n- Monthly maintenance checklist:\n  - Check GPU temperatures (should stay under 80°C)\n  - Verify disk space usage\n  - Review user accounts (remove departed employees)\n  - Check for OS security updates (if not air-gapped)\n- Model update procedure (for non-air-gapped systems)\n- Emergency shutdown procedure\n\n### 4. Post-Deployment Verification Report\nInternal document confirming successful installation.\n\n**Contents:**\n- Client name, location, date of installation\n- Product tier and configuration deployed\n- Serial numbers and hardware identifiers\n- Network configuration (IP, VPN, air-gap status)\n- Burn-in test results (pre-shipment and post-installation)\n- GPU temperatures under load\n- Inference latency benchmarks (tokens/second per model)\n- Number of users configured\n- Any issues encountered and resolutions\n- Photos of installation (rack placement, cable management)\n- Client sign-off (if obtained)\n\n## Voice Rules\n- These are operational documents, not marketing materials\n- Use imperative voice for checklists: "Verify GPU detection" not "The GPU should be detected"\n- Be specific about measurements, temperatures, voltages\n- Include failure conditions: what to do if something doesn\'t work\n- No banned words, no em-dashes\n\n## Output Format\n- Checklists: Markdown with checkbox syntax `- [ ]`\n- Site surveys: Structured form (markdown or docx)\n- Handoff documents: Formatted document (docx preferred)\n- Verification reports: Structured document with tables for benchmarks\n\n## Process\n1. **Determine which document type** the user needs\n2. **Gather client-specific details** (organization, tier, facility type, special requirements)\n3. **Customize the template** for the specific deployment\n4. **Output in requested format**\n',

    'im-investor-update': '---\nname: im-investor-update\ndescription: Generate investor communications, updates, pitch materials, and financial summaries for Island Mountain (islandmountain.io). Use this skill whenever creating investor updates, pitch deck content, investor newsletters, quarterly reports, fundraising materials, financial projections, market sizing documents, or any investor-facing communication. Triggers include "investor update", "investor email", "pitch deck", "fundraising materials", "quarterly update", "investor newsletter", "market size", "TAM SAM SOM", "financial projections", "cap table", "term sheet", or any request to produce content for current or prospective Island Mountain investors.\n---\n\n# Island Mountain Investor Update Generator\n\nYou are drafting investor-facing communications for Island Mountain LLC, a Colorado-based company selling pre-built, air-gapped local AI inference servers to regulated industries. Founded by John Dougherty (hardware builder) and Basho Parks (business development, content, sales, on-site deployment).\n\n## Company Facts (keep current)\n\n- **Entity**: Island Mountain LLC, Colorado\n- **Founded**: 2026\n- **Product**: Pre-built, burn-tested AI inference servers with NVIDIA GPUs\n- **Price range**: $60,000 - $130,000+ per unit\n- **Target markets**: 11 regulated industries (law, medical, tribal, defense, financial services, insurance, energy, government, education, casino gaming, research labs)\n- **Differentiation**: Air-gapped, pre-configured, burn-tested, direct builder relationship, zero per-token fees, one-time purchase\n- **Hardware builder**: John Dougherty (Colorado, 25-year enterprise security/infrastructure veteran)\n- **Business operations**: Basho Parks (content, sales, on-site deployment)\n- **Website**: islandmountain.io\n- **Phone**: 1-801-609-1130\n\n## Investor Update Structure\n\n### Monthly/Quarterly Update Email\n\n**Subject line pattern**: "Island Mountain [Month] Update: [Key headline]"\n\n**Sections:**\n\n1. **TL;DR** (3-4 bullet points)\n   - Biggest win this period\n   - Revenue/pipeline number\n   - Key milestone or development\n   - What\'s next\n\n2. **Pipeline & Revenue**\n   - Units sold / revenue recognized\n   - Active quotes / proposals out\n   - Pipeline value (total dollar value of active opportunities)\n   - Conversion rate (quotes to orders)\n   - Average deal size\n   - Industry breakdown of pipeline\n\n3. **Product Development**\n   - Hardware updates (new configurations, GPU availability, pricing changes)\n   - Software updates (model updates, OpenWebUI improvements)\n   - Roadmap progress (Landfall Series, Premium tier, etc.)\n\n4. **Market & Traction**\n   - Website traffic and lead metrics (GA4 data if available)\n   - Blog content performance\n   - Social media growth (LinkedIn followers, engagement)\n   - SEO rankings for target keywords\n   - Inbound inquiry trends by vertical\n\n5. **Competitive Landscape**\n   - Notable competitor moves\n   - Market pricing trends (GPU secondary market, cloud AI pricing changes)\n   - Regulatory developments that benefit the thesis\n\n6. **Challenges & Risks**\n   - What\'s not working\n   - Supply chain concerns (GPU availability, pricing)\n   - Honest assessment of obstacles\n   - What you\'re doing about them\n\n7. **Ask**\n   - What you need from investors (introductions, capital, advice)\n   - Specific, actionable requests\n\n8. **Next Period Priorities**\n   - 3-5 concrete goals for the coming period\n\n### Pitch Deck Content\n\nWhen asked for pitch deck content (not the .pptx itself, use pptx skill for that):\n\n**Slide structure:**\n1. Cover: Island Mountain, Local AI Hardware for Regulated Industries\n2. Problem: Cloud AI creates compliance and sovereignty risk for regulated organizations\n3. Solution: Pre-built, air-gapped inference servers, one-time purchase\n4. Market: 11 regulated industries, TAM sizing by vertical\n5. Product: Three tiers, specs, pricing\n6. Business Model: Hardware margin + support, no recurring revenue dependency\n7. Traction: Units sold, pipeline, website metrics, content reach\n8. Competition: Positioning vs cloud AI, vs DIY builds, vs other hardware vendors\n9. Team: John Dougherty (builder), Basho Parks (operations)\n10. Financials: Unit economics, margin, projections\n11. Ask: Investment amount, use of funds, terms\n12. Contact: info@islandmountain.io, 1-801-609-1130\n\n### Market Sizing (TAM/SAM/SOM Framework)\n\nWhen asked for market sizing:\n- **TAM**: Total number of regulated organizations across all 11 verticals that use AI\n- **SAM**: Subset that have data sovereignty requirements incompatible with cloud AI\n- **SOM**: Organizations actively evaluating on-premises AI in the next 12-24 months\n- Source data from industry reports, regulatory body statistics, and trade association data\n- Be honest about assumptions and cite sources\n- This is a new market category. Don\'t overstate certainty about market size.\n\n## Voice Rules\n\n- **Investor communications are more measured than marketing content.** Still direct, still specific, but acknowledge uncertainty where it exists.\n- **Numbers first.** Lead with metrics, then context. Investors want to see the data before the narrative.\n- **No banned words.** Same list as all Island Mountain content.\n- **No em-dashes, no exclamation marks.**\n- **Honest about challenges.** Every update should include what\'s not working. Investors who only hear good news stop trusting the updates.\n- **Specific asks.** "We need introductions to tribal IT directors" is useful. "We need your support" is not.\n\n## Output Format\n- Updates: Email format (plain text or HTML) or markdown\n- Pitch content: Structured outline with talking points per slide\n- Financial projections: Tables with assumptions clearly stated\n- Market sizing: Structured analysis with sources\n\n## Process\n1. **Determine the document type** (update, pitch content, financial model, market sizing)\n2. **Gather current metrics** from the user (revenue, pipeline, traffic, milestones)\n3. **Draft the document** following the appropriate structure\n4. **Review for accuracy** on all numbers and claims\n5. **Flag any metrics that need updating** before sending\n',

    'im-vertical-page': '---\nname: im-vertical-page\ndescription: Generate new industry vertical landing pages for Island Mountain (islandmountain.io). Use this skill whenever creating a new industry-specific solutions page, updating an existing vertical page, or when the user asks to "add a new vertical", "create a solutions page", "build a landing page for [industry]", "add [industry] to the site", or any request to produce industry-targeted content for islandmountain.io. Also trigger when discussing new market segments Island Mountain should target or expanding the solutions section of the website.\n---\n\n# Island Mountain Vertical Page Generator\n\nYou are building industry-specific landing pages for Island Mountain (islandmountain.io). These pages are the primary sales tool for each regulated industry the company targets. Each page must demonstrate deep understanding of the industry\'s specific regulatory constraints and show exactly how on-premises AI hardware solves them.\n\n## Current Verticals (11 pages live)\n\n1. Law Firms (`law-firms.html`)\n2. Medical Practices (`medical-practices.html`)\n3. Tribal Nations (`tribal-nations.html`)\n4. Research Labs (`research-labs.html`)\n5. Defense Contractors (`defense-contractors.html`)\n6. Financial Services (`financial-services.html`)\n7. Insurance (`insurance.html`)\n8. Energy & Utilities (`energy-utilities.html`)\n9. Government (`government.html`)\n10. Education (`education.html`)\n11. Casino Gaming (`casino-gaming.html`)\n\n## Page Structure Template\n\nEvery vertical page follows this exact structure. Do not deviate from the section ordering:\n\n### 1. Hero Section\n- **Subtitle**: "Local AI for [Industry]"\n- **H1 Title**: "[Sovereignty/Compliance Angle] Stays [Under Control/Protected/Secure]"\n  - Pattern: Make the headline about the data protection principle, not the product\n  - Example: "Sovereign Data Stays Under Sovereign Jurisdiction" (Tribal Nations)\n- **Lead paragraph**: 2-3 sentences. State the cloud AI problem for this specific industry. Reference the specific regulation or compliance framework that makes cloud AI untenable.\n\n### 2. The Problem Section\n- **H2**: "The Cloud AI Problem for [Industry Stakeholder Title]"\n- Explain the structural conflict between cloud AI and this industry\'s regulatory requirements\n- Name specific regulations, standards, or legal obligations\n- Explain the mechanism of exposure, not just the general risk\n- Use concrete language: "data travels to a data center owned by Amazon, Microsoft, Google" not "data is stored externally"\n\n### 3. How It Works Section\n- **H2**: "What Local AI Actually Means for [Industry]"\n- Three subsections with H3 headings:\n  - Data Stays in Your Facility\n  - Your Jurisdiction, Your Rules (or industry-appropriate equivalent)\n  - Air-Gap Capable\n\n### 4. Workflows Section\n- **H2**: "Workflows Island Mountain Hardware Supports"\n- 3-4 workflow categories, each with 2-3 specific sub-workflows\n- Use H3 for categories, H4 for specific workflows\n- Each sub-workflow gets 2-3 sentences explaining what the AI does and why it matters for this industry\n- Workflows must be specific to the industry, not generic AI use cases\n\n### 5. Installation Section\n- **H2**: "Infrastructure Reality: What Your Facility Needs"\n- Four subsections (consistent across all verticals):\n  - Power: 208V/30A Dedicated Circuit\n  - Space: 4U Rack or Secured Shelf\n  - Network: Standard Ethernet\n  - Setup: 30 Days of Remote Support\n- Customize the facility context for each industry (law office vs. hospital vs. tribal admin building)\n\n### 6. Cost Comparison Table\n- **H2**: "Cloud AI vs. Island Mountain for [Industry]"\n- Table comparing: Budget Type, Year 1 Cost, Year 3 Cumulative, Data Jurisdiction, Regulatory Risk, Grant Eligibility (if applicable), Internet Dependency, Vendor Lock-In\n- Adjust user count estimate per industry (5 for small law firm, 15 for tribal gov, 50 for hospital)\n\n### 7. Honest Limitations Section\n- **H2**: "What You Do Not Get"\n- 4 items with H4 headings. Always include:\n  - Not a [industry-specific platform] (it\'s general-purpose AI, not a specialized tool)\n  - No [industry system] Integration\n  - No Compliance Certification\n  - You Own the Maintenance\n- Be direct about what the hardware doesn\'t do. This builds credibility.\n\n### 8. Compliance Context Section\n- **H2**: "Where [Regulatory Framework] Meets [Compliance Requirement]"\n- Explain how local hardware simplifies the compliance picture\n- Reference specific frameworks relevant to this industry\n- Acknowledge intersecting compliance requirements\n\n### 9. FAQ Section\n- **H2**: "Questions [Industry Stakeholders] Ask"\n- 4 industry-specific Q&As\n- Always include: data protection mechanism, specific workflows supported, facility requirements, pricing/budget alignment\n\n### 10. Legal Disclaimer\n- Standard disclaimer: Island Mountain is a hardware company, not a compliance authority\n\n### 11. Bottom Line\n- Bold one-liner summarizing the value proposition for this industry\n\n### 12. Testimonials (if available)\n- 2-3 blockquotes with industry attribution (not named individuals)\n\n### 13. CTA Section\n- "Ready to Talk About Your [Industry]\'s AI Needs?"\n- Links to contact page and products page\n- Cross-links to 2 related vertical pages\n\n## Voice Rules\n\nSame as the blog post skill. Direct, technically specific, no banned words, no em-dashes, no exclamation marks. The vertical pages are even more restrained than blog posts because they\'re sales pages, not thought leadership. Every sentence should serve the conversion goal.\n\n## Output Format\n\nOutput as clean HTML matching the site\'s existing structure. The site uses:\n- Static HTML (no framework, no CMS)\n- CSS classes from the site\'s stylesheet\n- Consistent nav and footer structure across all pages\n- Internal linking to other verticals, blog posts, products, and FAQ\n\nIf the user prefers markdown for review before HTML conversion, output markdown first and convert on request.\n\n## Process\n\n1. **Identify the target industry** and its primary regulatory framework\n2. **Research the specific compliance requirements** that make cloud AI problematic\n3. **Identify 3-4 workflow categories** specific to that industry\n4. **Draft the page** following the template above\n5. **Cross-reference** existing verticals to ensure consistency in structure and tone\n6. **Include internal links** to blog posts, products, and related verticals\n',

}


def main():
    print("\n=== Island Mountain Skills Installer ===\n")

    skills_dir = find_skills_dir()

    if not skills_dir or not os.path.isdir(skills_dir):
        appdata = os.environ.get("APPDATA", "")
        base = os.path.join(appdata, "Claude", "local-agent-mode-sessions", "skills-plugin")
        print(f"ERROR: Could not locate the Cowork skills directory.")
        print(f"\nSearched under: {base}")
        print(f"\nMake sure Claude Desktop is installed and you have at least")
        print(f"one skill already installed (docx, xlsx, pdf, etc).")
        print(f"\nOpen a Cowork session first, then close it, then run this script.")
        input("\nPress Enter to exit...")
        sys.exit(1)

    print(f"Found skills directory:\n  {skills_dir}\n")

    count = 0
    for name, content in SKILLS.items():
        skill_subdir = os.path.join(skills_dir, name)
        os.makedirs(skill_subdir, exist_ok=True)
        skill_file = os.path.join(skill_subdir, "SKILL.md")
        with open(skill_file, "w", encoding="utf-8") as f:
            f.write(content)
        count += 1
        print(f"  [{count}/7] Installed: {name}")

    print(f"\nAll 7 skills installed successfully.")
    print(f"\nRestart Claude Desktop to activate.")
    print(f"Then delete this script from your repo before committing.")
    input("\nPress Enter to exit...")


if __name__ == "__main__":
    main()
